final:
module top_module(
    input [3:0] D,
    input SHL,
    input SHR,
    input LOAD,
    input clk, // Added clk input
    output reg [3:0] Q
);reg [3:0] X_Q_reg;
reg [3:0] Q_next;

always @(*) begin
    Q_next = X_Q_reg;
    if (LOAD) begin
        Q_next = D;
    end else if (SHL) begin
        Q_next = {X_Q_reg[2:0], 1'b0};
    end else if (SHR) begin
        Q_next = {1'b0, X_Q_reg[3:1]};
    end
end

always @(posedge clk) begin
    X_Q_reg <= Q_next;
end

assign Q = X_Q_reg;

endmodule
